backend.config:
formats => ['csv','xlsx'] (abilitati; guida Rule::in + factory writer);
disk => 'local'; directory => 'exports';
max_rows => (int) env('EXPORT_MAX_ROWS', 100000);   // cap difensivo memoria/tempo
chunk_size => (int) env('EXPORT_CHUNK_SIZE', 1000);  // cursor/lazy chunk
writers => [ 'csv' => CsvExportWriter::class, 'xlsx' => XlsxExportWriter::class ]. // registry OCP

