backend.job:
implements ShouldQueue; ctor `private readonly int $exportRunId`. handle(ExportService $service):
$run = ExportRun::findOrFail($id); try { $service->generate($run); } catch (Throwable $e) {
$run->update(['status'=>Failed]); throw $e; }.
